import{_ as s,o as a,c as t,a2 as r}from"./chunks/framework.D2pTuMig.js";const p=JSON.parse('{"title":"Gestion des Campagnes","description":"","frontmatter":{"title":"Gestion des Campagnes"},"headers":[],"relativePath":"docs/fr/faq/campaign-management.md","filePath":"docs/fr/faq/campaign-management.md"}'),i={name:"docs/fr/faq/campaign-management.md"};function n(o,e,l,u,d,m){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="gestion-des-campagnes" tabindex="-1">Gestion des Campagnes <a class="header-anchor" href="#gestion-des-campagnes" aria-label="Permalink to &quot;Gestion des Campagnes&quot;">​</a></h1><details class="details custom-block"><summary>Quel est le délai de réponse attendu ?</summary><p>Vous devez répondre sous <strong>48 heures ouvrées</strong>. La réactivité est la clé pour remporter les campagnes face aux autres retailers. Passé ce délai, getinside se réserve le droit de refuser la campagne en votre nom et d&#39;appliquer une pénalité correspondante aux frais de plateforme prévus.</p></details><details class="details custom-block"><summary>Puis-je annuler une campagne déjà acceptée ?</summary><p>L&#39;annulation est fortement déconseillée. Sauf force majeure, des pénalités s&#39;appliquent :</p><ul><li>Pénalité forfaitaire de <strong>250€</strong></li><li>+ Remboursement des frais de plateforme perdus</li><li>+ Remboursement des frais de production (si imprimé) et de studio engagés</li></ul></details><details class="details custom-block"><summary>Puis-je refuser d&#39;insérer un flyer reçu ?</summary><p>Oui. Vérifiez la marchandise à réception. Si les supports sont endommagés ou non conformes au BAT validé (ex : marque concurrente non signalée), contactez immédiatement le support (<code>studio@getinside.fr</code>) et suspendez l&#39;insertion.</p></details><details class="details custom-block"><summary>La campagne démarre en retard — que faire ?</summary><p>Si vous n&#39;avez rien distribué sur une semaine prévue :</p><ol><li>Saisissez <strong>&quot;0&quot;</strong> dans le reporting de la semaine.</li><li>Prévenez l&#39;annonceur via la messagerie.</li></ol><p>La plateforme prolongera automatiquement la campagne en fin de période pour atteindre le volume cible.</p></details><details class="details custom-block"><summary>Comment ajouter un nouveau type d&#39;offre ?</summary><p>Allez sur la fiche de l&#39;audience concernée et ajoutez un type de campagne. Pour une offre sur-mesure (hors catalogue standard), sélectionnez <strong>&quot;Autre type de campagne&quot;</strong> — l&#39;équipe getinside validera la faisabilité avec vous.</p></details><details class="details custom-block"><summary>Où voir l&#39;historique de mes campagnes ?</summary><ul><li><strong>Campagnes reçues (Retailer) :</strong> Monétisation → Gestionnaire de campagne (filtrez par statut : Accepté, Refusé…)</li><li><strong>Vos propres campagnes (Annonceur) :</strong> Campagnes → Toutes les campagnes</li></ul></details><details class="details custom-block"><summary>Comment suivre les performances de ma campagne ?</summary><p>Vous disposez d&#39;un double suivi sur votre tableau de bord getinside :</p><ol><li><strong>Performance (ROI) :</strong> Scans de vos QR codes en temps réel.</li><li><strong>Distribution :</strong> Volumes de flyers insérés mis à jour chaque début de semaine par le distributeur.</li></ol></details><details class="details custom-block"><summary>Un distributeur refuse mon visuel — que faire ?</summary><p>Le distributeur a un <strong>droit de veto sur la marque</strong> (concurrent direct, catégorie éthiquement incompatible) — mais pas sur la direction artistique.</p><p>Si votre visuel respecte les spécifications techniques (fond perdu 2mm, zone tranquille 3mm, résolution 300 DPI, mentions légales présentes), il est conforme. Le distributeur ne peut pas le rejeter pour des raisons subjectives de goût ou de style.</p><p><strong>Marche à suivre :</strong></p><ol><li>Vérifiez que votre fichier respecte bien les <a href="/handbook/docs/fr/advertisers/sponsored-mail/design-guide/print-specs.html">spécifications d&#39;impression</a>.</li><li>Si tout est conforme, transmettez votre BAT à <a href="mailto:studio@getinside.fr" target="_blank" rel="noreferrer">studio@getinside.fr</a> pour validation officielle.</li><li>La validation getinside prime sur l&#39;appréciation subjective du distributeur.</li></ol></details><details class="details custom-block"><summary>Un annonceur me demande les adresses de mes clients — puis-je les donner ?</summary><p><strong>Non, en aucun cas.</strong> Cette demande est contraire au RGPD et à nos CGU.</p><p>Vos données clients sont un actif <strong>First Party</strong> qui vous appartient exclusivement. getinside opère comme <strong>Tiers de Confiance</strong> : l&#39;annonceur accède à votre audience sans jamais recevoir le fichier. Aucun transfert de base n&#39;est autorisé sans opt-in spécifique de chaque client.</p><p>En cas de demande insistante, contactez <a href="mailto:support@getinside.fr" target="_blank" rel="noreferrer">support@getinside.fr</a> — notre équipe prend en charge la réponse légale.</p></details>',10)])])}const g=s(i,[["render",n]]);export{p as __pageData,g as default};
